import{_ as s,o as i,c as e,ah as n}from"./chunks/framework.CkJUk41Q.js";const c=JSON.parse('{"title":"Git","description":"","frontmatter":{"title":"Git","order":20},"headers":[],"relativePath":"sde/git/index.md","filePath":"sde/git/index.md"}'),t={name:"sde/git/index.md"};function p(l,a,h,o,r,d){return i(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="git" tabindex="-1">Git <a class="header-anchor" href="#git" aria-label="Permalink to “Git”">​</a></h1><p>Git 是分布式版本控制系统，是现代软件工程的基础设施。Git 记录代码的所有变更历史，支持多人协作开发，提供分支管理、代码审查、版本回退等功能。</p><h2 id="约定式提交" tabindex="-1">约定式提交 <a class="header-anchor" href="#约定式提交" aria-label="Permalink to “约定式提交”">​</a></h2><p>约定式提交（Conventional Commits）规范提交信息格式，使提交历史清晰易读。</p><h3 id="提交类型" tabindex="-1">提交类型 <a class="header-anchor" href="#提交类型" aria-label="Permalink to “提交类型”">​</a></h3><p>feat：新功能、新特性</p><p>fix：修改 bug</p><p>perf：更改代码，以提高性能（在不影响代码内部行为的前提下，对程序性能进行优化）</p><p>refactor：代码重构（重构，在不影响代码内部行为、功能下的代码修改）</p><p>docs：文档修改</p><p>style：代码格式修改，注意不是 css 修改（例如分号修改）</p><p>test：测试用例新增、修改</p><p>build：影响项目构建或依赖项修改</p><p>revert：恢复上一次提交</p><p>ci：持续集成相关文件修改</p><p>chore：其他修改（不在上述类型中的修改）</p><p>release：发布新版本</p><p>workflow：工作流相关文件修改</p><h3 id="提交格式" tabindex="-1">提交格式 <a class="header-anchor" href="#提交格式" aria-label="Permalink to “提交格式”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&lt;type&gt;(&lt;scope&gt;): &lt;subject&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;body&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;footer&gt;</span></span></code></pre></div><p>type 是提交类型，scope 是影响范围（可选），subject 是简短描述（不超过 50 字符）。</p><p>示例：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>feat(auth): add JWT authentication</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Implement JWT-based authentication with access token and refresh token.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Add login endpoint</span></span>
<span class="line"><span>- Add token refresh endpoint</span></span>
<span class="line"><span>- Add middleware for token validation</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Closes #123</span></span></code></pre></div><h2 id="git-分支管理" tabindex="-1">Git 分支管理 <a class="header-anchor" href="#git-分支管理" aria-label="Permalink to “Git 分支管理”">​</a></h2><h3 id="git-flow" tabindex="-1">Git Flow <a class="header-anchor" href="#git-flow" aria-label="Permalink to “Git Flow”">​</a></h3><p>Git Flow 是经典的分支管理策略，适合有明确发布周期的项目。</p><p>main：主分支，只包含稳定发布版本</p><p>develop：开发分支，集成所有功能开发</p><p>feature：功能分支，从 develop 分支，完成后合并回 develop</p><p>release：发布分支，从 develop 分支，准备发布时使用</p><p>hotfix：修复分支，从 main 分支，紧急修复使用</p><h3 id="github-flow" tabindex="-1">GitHub Flow <a class="header-anchor" href="#github-flow" aria-label="Permalink to “GitHub Flow”">​</a></h3><p>GitHub Flow 是简化的分支管理策略，适合持续部署项目。</p><p>main：主分支，始终可部署</p><p>feature：功能分支，从 main 分支，通过 PR 合并到 main</p><h3 id="trunk-based-development" tabindex="-1">Trunk Based Development <a class="header-anchor" href="#trunk-based-development" aria-label="Permalink to “Trunk Based Development”">​</a></h3><p>基于主干的开发，所有开发在主分支进行，频繁发布。</p><h2 id="git-hook" tabindex="-1">Git Hook <a class="header-anchor" href="#git-hook" aria-label="Permalink to “Git Hook”">​</a></h2><p>Git Hook 是 Git 在特定事件触发的脚本，可用于代码检查、自动测试、格式化等。</p><h3 id="常用-hook" tabindex="-1">常用 Hook <a class="header-anchor" href="#常用-hook" aria-label="Permalink to “常用 Hook”">​</a></h3><p>pre-commit：提交前触发，可用于代码格式检查、运行测试</p><p>commit-msg：提交信息编辑后触发，可用于验证提交格式</p><p>pre-push：推送前触发，可用于运行完整测试套件</p><h3 id="husky" tabindex="-1">Husky <a class="header-anchor" href="#husky" aria-label="Permalink to “Husky”">​</a></h3><p>Husky 是 Git Hook 管理工具，简化 Hook 配置。</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;husky&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;hooks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;pre-commit&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;npm run lint&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;commit-msg&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;commitlint -E HUSKY_GIT_PARAMS&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="git-最佳实践" tabindex="-1">Git 最佳实践 <a class="header-anchor" href="#git-最佳实践" aria-label="Permalink to “Git 最佳实践”">​</a></h2><p>频繁提交：小步快跑，每次提交包含一个完整的逻辑单元</p><p>清晰提交：提交信息准确描述变更内容，便于历史追溯</p><p>原子提交：每次提交只做一件事，不包含无关变更</p><p>审查合并：代码审查通过后再合并到主分支</p><p>保持干净：定期清理已合并的分支，保持分支列表简洁</p><p>Git 是工程化的基础，理解 Git 的工作原理和最佳实践，有助于高效协作开发。</p>`,53)])])}const g=s(t,[["render",p]]);export{c as __pageData,g as default};
